INSERT OR REPLACE INTO applications VALUES(2,'JomSoft Sdn Bhd','FullStack Developer - NodeJS & Angular','Applied',replace(replace('ZAFRAN BIN MUHAMAD SAKOWI\r\nSelangor, MY | +60 165972862 | zafransakowi@gmail.com\r\nzafran-sakowi.my | linkedin.com/in/zafran-sakowi/\r\nEDUCATION\r\nUNIVERSITY TEKONOLOGI MALAYSIA\r\nBachelor of Computer Science (Software Engineering) with Honours\r\nCumulative GPA: 3.79/4.0; Dean’s List 2022-2026\r\nJohor, MY\r\nGraduate Aug 2026\r\nSKILL\r\n● Languages & Frameworks: Java (Spring Boot), Python (learning), JavaScript (Next.js, React Native)\r\n● Cloud & DevOps: Docker, Linux (Ubuntu Server), Git/GitHub Actions, RESTful APIs, CI/CD Pipelines\r\n● Data & Databases: MySQL (T-SQL Optimization), Hibernate ORM,Postgres, TFLite |Tooling: Postman, VS Code\r\nSoft Skills: Team Leadership & Collaboration, Project Management, Agile Methodology, cross-functional communication,\r\nProblem Solving, Community Development\r\nWORK EXPERIENCE\r\nCipta Craft Solutions\r\nJohor,MY\r\nFreelancer Full-Stack Developer\r\nJun 2025 – Present\r\n● Developed XFitness, a cross-platform fitness membership platform using Next.js 15, achieving a 30% SE','\r',char(13)),'\n',char(10)),replace('Subject: Zafran Bin Muhamad Sakowi - Full-Stack Developer | Driving Web Application Performance & SDLC Excellence\n\nThe opportunity for a Software Engineer focused on web application development has deeply captured my interest. With a robust background in designing, developing, and maintaining high-performance web solutions, I am confident my comprehensive skill set and practical experience align perfectly with your team’s requirements for delivering applications within defined quality and performance standards.\n\nMy experience as a Freelance Full-Stack Developer at Cipta Craft Solutions directly reflects your need for adept web application development. I successfully developed XFitness using Next.js 15, achieving a 30% SEO score improvement through Server-Side Rendering optimization and automating client workflows to eliminate 15 hours/week of manual administrative overhead. Furthermore, my IT (Software Developer) Internship at Mattel Malaysia Sdn Bhd involved optimizing high-traffic manufacturing dashboards, reducing data retrieval latency by 94% through T-SQL indexing, showcasing my commitment to achieving high performance and taking ownership of code quality.\n\nI am well-versed in participating throughout the entire SDLC, from analysis and design to deployment and maintenance. At Cipta Craft, I directed a 5-person team across product sprints, utilizing GitHub branching and automated test suites to ensure timely and quality deliverables. My collaboration with cross-functional teams to migrate legacy modules to modern MVC architecture at Mattel, which reduced average page load times by 40%, exemplifies my proactive approach to process improvement and my ability to share knowledge effectively with stakeholders.\n\nI am eager to discuss how my proven ability to architect and deliver robust, efficient web applications, coupled with my strong foundation in technologies like Spring Boot, Next.js, Docker, and CI/CD pipelines, can contribute significantly to your team''s success. Thank you for considering my application, and I look forward to the possibility of an interview.','\n',char(10)),'2026-05-24 09:33:52.433397',NULL,'ai_generated');
