INSERT OR REPLACE INTO applications VALUES(4,'UTOPIA HOLDING SDN.BHD Kuala Lumpur RM 3,500 - RM 6,000 a month - Full-time UTOPIA HOLDING SDN.BHD','Software Developer (AI Driven Systems) - job post','Applied',replace(replace('ZAFRAN BIN MUHAMAD SAKOWI\r\nSelangor, MY | +60 165972862 | zafransakowi@gmail.com\r\nzafran-sakowi.my | linkedin.com/in/zafran-sakowi/\r\nEDUCATION\r\nUNIVERSITY TEKONOLOGI MALAYSIA\r\nBachelor of Computer Science (Software Engineering) with Honours\r\nCumulative GPA: 3.79/4.0; Dean’s List 2022-2026\r\nJohor, MY\r\nGraduate Aug 2026\r\nSKILL\r\n● Languages & Frameworks: Java (Spring Boot), Python (learning), JavaScript (Next.js, React Native)\r\n● Cloud & DevOps: Docker, Linux (Ubuntu Server), Git/GitHub Actions, RESTful APIs, CI/CD Pipelines\r\n● Data & Databases: MySQL (T-SQL Optimization), Hibernate ORM,Postgres, TFLite |Tooling: Postman, VS Code\r\nSoft Skills: Team Leadership & Collaboration, Project Management, Agile Methodology, cross-functional communication,\r\nProblem Solving, Community Development\r\nWORK EXPERIENCE\r\nCipta Craft Solutions\r\nJohor,MY\r\nFreelancer Full-Stack Developer\r\nJun 2025 – Present\r\n● Developed XFitness, a cross-platform fitness membership platform using Next.js 15, achieving a 30% SE','\r',char(13)),'\n',char(10)),replace('Subject: Propelled by AI & Full-Stack Development: Zafran Sakowi for Your Software Team\n\nDear Hiring Manager,\n\nThe opportunity to contribute to your dynamic team, particularly as you transition towards an AI-first approach for your extensive internal systems, immediately captured my attention. My enthusiasm stems from a deep alignment with your mission to build impactful web and mobile applications that drive efficiency across 30+ businesses. I am eager to apply my full-stack development expertise and passion for innovation to your challenging projects.\n\nMy background as a Full-Stack Developer, evidenced by projects like developing the XFitness platform with Next.js 15 and React Native, directly parallels your need to build robust web and mobile features. I''ve consistently demonstrated proficiency in connecting front-end interfaces to backend APIs and managing database operations, including T-SQL optimization during my internship at Mattel Malaysia. Crucially, my work on the FloraScan AI-Powered Diagnostic Tool, where I engineered an edge-compatible mobile solution using TFLite and React Native, reflects a strong foundation and genuine passion for integrating AI into real business workflows and improving automation.\n\nI am particularly drawn to the prospect of not just maintaining code, but actively building real modules that will significantly enhance operations for your diverse group of businesses. My experience automating client billing workflows at Cipta Craft Solutions, eliminating 15 hours/week of manual overhead, exemplifies my commitment to leveraging technology for tangible operational improvements. I am confident my proficiency in JavaScript, TypeScript, and database concepts, combined with a proactive approach to problem-solving, makes me an ideal candidate to contribute to your team''s success from day one.\n\nI am eager to discuss how my full-stack capabilities, combined with a genuine drive to innovate in AI and automation, can contribute meaningfully to your team''s goals. Please feel free to reach out to schedule a conversation at your earliest convenience.\n\nSincerely,\nZafran Bin Muhamad Sakowi','\n',char(10)),'2026-05-24 09:52:38.216119',NULL,'ai_generated');
INSERT OR REPLACE INTO applications VALUES(11,'iCompuCARE Global Services Sdn Bhd','Onsite IT Engineer - job post','Applied',replace(replace('EDUCATION\r\nUNIVERSITY TEKONOLOGI MALAYSIA\r\nBachelor of Computer Science (Software Engineering) with Honours\r\nCumulative GPA: 3.79/4.0; Dean’s List 2022-2026\r\nJohor, MY\r\nGraduate Aug 2026\r\nSKILL\r\n● Languages & Frameworks: Java (Spring Boot), Python (learning), JavaScript (Next.js, React Native)\r\n● Cloud & DevOps: Docker, Linux (Ubuntu Server), Git/GitHub Actions, RESTful APIs, CI/CD Pipelines\r\n● Data & Databases: MySQL (T-SQL Optimization), Hibernate ORM,Postgres, TFLite |Tooling: Postman, VS Code\r\nSoft Skills: Team Leadership & Collaboration, Project Management, Agile Methodology, cross-functional communication,\r\nProblem Solving, Community Development\r\nWORK EXPERIENCE\r\nCipta Craft Solutions\r\nJohor,MY\r\nFreelancer Full-Stack Developer\r\nJun 2025 – Present\r\n● Developed XFitness, a cross-platform fitness membership platform using Next.js 15, achieving a 30% SEO score improvement\r\nthrough Server-Side Rendering and React Server Component optimization across 5 core pages.\r\n● Automated client b','\r',char(13)),'\n',char(10)),replace('Subject: Applying for Support Engineer | Deep Technical Insight for Onsite Client Success\n\nDear [Hiring Manager Name],\n\nI am reaching out with genuine enthusiasm for the Support Engineer position. My background in Software Engineering, coupled with a passion for problem-solving and optimizing systems, aligns perfectly with your requirement for a proactive individual to diagnose, troubleshoot, and resolve technical issues at client premises. I am eager to transition my robust understanding of system architecture and performance into a hands-on, client-facing support role, ensuring optimal and secure IT setups.\n\nMy experience, particularly in optimizing manufacturing dashboards to reduce data retrieval latency by 94% at Mattel Malaysia and automating client workflows at Cipta Craft Solutions, demonstrates a strong capacity for identifying root causes and implementing robust solutions. I have a proven track record of enabling non-technical staff through training and system improvements, and my work on secure audit trail systems and Role-Based Access Control (RBAC) frameworks directly reflects the need for maintaining system integrity and cybersecurity. While my primary experience is in development and deployment (Docker, Linux), I am confident in applying this deep technical understanding to installing, configuring, and maintaining IT equipment, and I am keen to leverage my analytical skills for comprehensive system evaluations and preventive maintenance.\n\nI am highly motivated by the opportunity to build strong client relationships and contribute to operational efficiency through dedicated onsite support, including meticulous documentation and reporting. My unique blend of software development expertise and a proactive, problem-solving mindset will allow me to bring a fresh perspective to your team. I have attached my resume for your review and welcome the chance to discuss how my skills and enthusiasm can benefit your clients.','\n',char(10)),'2026-05-24 11:13:07.240088',NULL,'ai_generated');
INSERT OR REPLACE INTO applications VALUES(12,'eKomas','Junior Software Engineer (Entry Level) - job post','Applied',replace(replace('EDUCATION\r\nUNIVERSITY TEKONOLOGI MALAYSIA\r\nBachelor of Computer Science (Software Engineering) with Honours\r\nCumulative GPA: 3.79/4.0; Dean’s List 2022-2026\r\nJohor, MY\r\nGraduate Aug 2026\r\nSKILL\r\n● Languages & Frameworks: Java (Spring Boot), Python (learning), JavaScript (Next.js, React Native)\r\n● Cloud & DevOps: Docker, Linux (Ubuntu Server), Git/GitHub Actions, RESTful APIs, CI/CD Pipelines\r\n● Data & Databases: MySQL (T-SQL Optimization), Hibernate ORM,Postgres, TFLite |Tooling: Postman, VS Code\r\nSoft Skills: Team Leadership & Collaboration, Project Management, Agile Methodology, cross-functional communication,\r\nProblem Solving, Community Development\r\nWORK EXPERIENCE\r\nCipta Craft Solutions\r\nJohor,MY\r\nFreelancer Full-Stack Developer\r\nJun 2025 – Present\r\n● Developed XFitness, a cross-platform fitness membership platform using Next.js 15, achieving a 30% SEO score improvement\r\nthrough Server-Side Rendering and React Server Component optimization across 5 core pages.\r\n● Automated client b','\r',char(13)),'\n',char(10)),replace('Subject: Developer Application - [Candidate Name] - Leveraging Full-Stack and Back-End Expertise\n\nDear [Hiring Manager name, if known, otherwise Dear Hiring Team],\n\nI am genuinely excited by the Developer opportunity at your company, particularly the focus on coding, developing, and back-end system support. As a soon-to-be Bachelor of Computer Science (Software Engineering) graduate from Universiti Teknologi Malaysia with a 3.79 GPA and Dean''s List recognition, my academic foundation aligns perfectly with your encouragement for fresh graduates seeking impactful entry-level roles.\n\nMy practical experience as a Freelance Full-Stack Developer at Cipta Craft Solutions, coupled with my IT Internship at Mattel Malaysia, has equipped me with robust skills in database optimization (MySQL T-SQL indexing), Linux environments (Ubuntu Server), and developing scalable RESTful APIs with Docker. While my primary back-end experience spans Java (Spring Boot) and Python (FastAPI), my extensive JavaScript proficiency (Next.js, React Native) and strong grasp of software architecture make me highly adaptable to contributing effectively with NodeJS and existing PHP systems. I am proficient in troubleshooting incidents and translating complex business requirements into functional solutions, as demonstrated by optimizing manufacturing dashboards and developing comprehensive ERP and diagnostic tools.\n\nI am eager to apply my proven problem-solving abilities and collaborative spirit to maintain and develop new systems, ensuring successful product delivery within estimated timeframes. The prospect of contributing to your innovative projects in Kuala Lumpur is particularly appealing. I am confident my technical acumen and passion for continuous learning would make me a valuable asset to your team, and I welcome the opportunity to discuss my qualifications further in an interview.\n\nThank you for your time and consideration.\n\nSincerely,\n[Candidate Name]','\n',char(10)),'2026-05-24 11:29:14.809029',NULL,'ai_generated');
